declaration, arguments, return values<pre><code># Two syntaxes — prefer the function keyword form
greet() { echo "Hello $1"; }            # POSIX style
function greet { echo "Hello $1"; }      # bash style
function greet() { echo "Hello $1"; }    # both (preferred)

# Arguments: same as script ($1, $2, ... $@, $#)
function add() {
  local a="$1"  local b="$2"
  echo "$(( a + b ))"  # return value via stdout
}
result=$(add 3 4)   # capture output: 7

# return — only sets exit code (0-255), NOT a value
function is_root() {
  [[ $EUID -eq 0 ]]  # return value is last command's exit code
}
is_root &amp;&amp; echo "running as root"

# local — critical for avoiding global variable leaks
function myfunc() {
  local tmp="$1"
  local -i count=0  # local integer
  local -a arr      # local array
  local -A map      # local assoc array
}

# Returning values via nameref (bash 4.3+) — avoids subshell overhead
function get_value() {
  local -n _ref="$1"  # nameref — _ref IS the variable named in $1
  _ref="computed value"
}
myvar=""
get_value myvar   # myvar is now "computed value" — no subshell!

# Recursion — with local for proper stack frames
function factorial() {
  local n="$1"
  [[ $n -le 1 ]] &amp;&amp; { echo 1; return; }
  echo $(( n * $(factorial $((n - 1))) ))
}

# List all defined functions
declare -F              # function names
declare -f myfunc      # function source code
</code></pre> <p>always use local</p> <p>Without local, variables in functions are global and will clobber outer scope variables with the same name. Make it a reflex to declare local for every function variable.</p> <p>nameref vs subshell return</p> <p>result=$(myfunc) spawns a subshell — can't modify the parent environment, costs a fork. Nameref (local -n) assigns directly into the caller's scope with no subshell. Prefer nameref for performance-critical loops.</p>

quoting rules<pre><code># Double quotes: variable expansion + command substitution, no word-split
echo "Hello $name, today is $(date)"

# Single quotes: NOTHING is expanded, literal string
echo '$HOME is literally $HOME — no expansion'

# $'...' — ANSI-C quoting, allows escape sequences
echo $'line1\nline2\ttabbed'
sep=$'\t'     # literal tab character
nul=$'\0'     # null byte

# RULE: ALWAYS double-quote variable expansions
# BAD:  cp $src $dst   (breaks if path has spaces)
# GOOD: cp "$src" "$dst"

# EXCEPTION: arithmetic context, [[ ]], and assignment RHS
if [[ $count -gt 0 ]]; then echo "ok"; fi  # fine unquoted inside [[]]
</code></pre> string operations<pre><code>s="Hello, World!"

# Length
echo "${#s}"           # 13

# Substring: ${var:offset:length}
echo "${s:7:5}"        # World
echo "${s:(-6)}"       # orld!  (negative = from end)

# Case conversion (bash 4+)
echo "${s,,}"           # hello, world!  (all lower)
echo "${s^^}"           # HELLO, WORLD!  (all upper)
echo "${s,}"            # hEllo, World!  (first char lower)
echo "${s^}"            # Hello, World!  (first char upper)

# Replace: ${var/pattern/replacement}
echo "${s/World/Bash}"   # Hello, Bash!   (first match)
echo "${s//l/L}"        # HeLLo, WorLd!  (all matches)
echo "${s/#Hello/Hi}"   # Hi, World!     (prefix match)
echo "${s/%!/...}"      # Hello, World...  (suffix match)

# Trim: # = prefix, % = suffix, ## / %% = greedy
path="/usr/local/bin/bash"
echo "${path##*/}"      # bash    (basename)
echo "${path%/*}"       # /usr/local/bin  (dirname)
file="archive.tar.gz"
echo "${file%.gz}"      # archive.tar     (strip .gz)
echo "${file%%.*}"      # archive         (strip all extensions)

# Test if contains substring
[[ "$s" == *"World"* ]] &amp;&amp; echo "contains World"

# Multiline string
multi="line one
line two
line three"

# Heredoc (assigned to var)
text=$(cat &lt;&lt;EOF
  Hello $name
  Today is $(date)
EOF
)
</code></pre>

( ) subshell vs { } group<pre><code># ( ) — subshell: forks a new process, changes are isolated
x=1
( x=99; cd /tmp; echo "$x" )   # prints 99
echo "$x"                       # still 1 — subshell change isolated
echo "$PWD"                     # original dir — cd isolated

# Use ( ) to isolate side-effects:
(
  cd /some/dir
  source env.sh         # won't pollute current env
  ./script.sh
)

# { } — command group: same shell, no fork, changes persist
{
  x=99
  echo "inside group"
}                        # note: semicolon/newline before }
echo "$x"               # 99 — change persists

# { } for grouping redirections (only one redirection needed)
{
  echo "header"
  cat data.txt
  echo "footer"
} &gt; output.txt

# { } for error handling group
{
  step1 &amp;&amp;
  step2 &amp;&amp;
  step3
} || {
  echo "pipeline failed"
  rollback
}

# Subshell pipeline variable scope trap
count=0
# WRONG: cmd runs in subshell, count changes lost
echo "a b c" | while read w; do ((count++))||true; done; echo $count  # 0!
# CORRECT: process substitution keeps parent shell
while read w; do ((count++))||true; done &lt; &lt;(echo "a b c"); echo $count  # 3
</code></pre>

